@Test
public void testEbeDivideZeroByZero() {
    RealVector v1 = create(new double[] {0.0, 1.0, 2.0});
    RealVector v2 = create(new double[] {0.0, 2.0, 4.0});
    RealVector result = v1.ebeDivide(v2);
    Assert.assertTrue(Double.isNaN(result.getEntry(0)));
    Assert.assertEquals(0.5, result.getEntry(1), 0.0);
    Assert.assertEquals(0.5, result.getEntry(2), 0.0);
}

@Test
public void testEbeMultiplyZeroByInfinity() {
    RealVector v1 = create(new double[] {0.0, 1.0, 0.0});
    RealVector v2 = create(new double[] {Double.POSITIVE_INFINITY, 2.0, Double.NEGATIVE_INFINITY});
    RealVector result = v1.ebeMultiply(v2);
    Assert.assertTrue(Double.isNaN(result.getEntry(0)));
    Assert.assertEquals(2.0, result.getEntry(1), 0.0);
    Assert.assertTrue(Double.isNaN(result.getEntry(2)));
}

@Test
public void testEbeMultiplyZeroByNaN() {
    RealVector v1 = create(new double[] {0.0, 1.0, 2.0});
    RealVector v2 = create(new double[] {Double.NaN, 3.0, 4.0});
    RealVector result = v1.ebeMultiply(v2);
    Assert.assertTrue(Double.isNaN(result.getEntry(0)));
    Assert.assertEquals(3.0, result.getEntry(1), 0.0);
    Assert.assertEquals(8.0, result.getEntry(2), 0.0);
}
